getDatabasesSql: SELECT datname AS name FROM pg_database WHERE datistemplate = false ORDER BY datname
getSchemasSql: SELECT schema_name AS name, catalog_name AS catalog, schema_owner AS owner FROM information_schema.schemata ORDER BY schema_name
getTypesSql: SELECT type.typname AS data_type, namespace.nspname AS schema FROM pg_type type JOIN pg_namespace namespace ON namespace.oid = type.typnamespace WHERE type.typtype IN ('b', 'c', 'd', 'e') AND namespace.nspname = 'public' ORDER BY namespace.nspname, type.typname
getTablesSql: SELECT c.relname AS table_name, CASE WHEN c.relkind IN ('v', 'm') THEN 'VIEW' ELSE 'BASE TABLE' END AS table_type,
n.nspname AS schema, c.oid, c.reltuples AS rows, CASE WHEN c.relkind IN ('v', 'm') THEN 1 ELSE 0 END AS is_view,
CASE WHEN p.partrelid IS NOT NULL THEN 1 ELSE 0 END AS partitioned FROM pg_class c JOIN pg_namespace n ON n.oid = c.relnamespace LEFT JOIN pg_partitioned_table p ON p.partrelid = c.oid WHERE c.relkind IN ('r', 'p', 'v', 'm') AND n.nspname NOT LIKE 'pg_%' AND n.nspname <> 'information_schema' AND n.nspname = 'public' ORDER BY n.nspname, c.relname
getColumnsSql: SELECT * FROM information_schema.columns WHERE table_name = 'users' AND table_schema = 'public' ORDER BY ordinal_position
getAllColumnsSql: SELECT * FROM information_schema.columns WHERE table_catalog = 'app' AND table_schema = 'public' ORDER BY table_schema, table_name, ordinal_position
getAllIndexesSql: SELECT namespace.nspname AS table_schema, table.relname AS table_name, index_rel.relname AS index_name, CASE WHEN index_data.indisprimary THEN 'PRIMARY' WHEN index_data.indisunique THEN 'UNIQUE' ELSE 'INDEX' END AS index_type, index_data.indisunique AS is_unique, access_method.amname AS algorithm, attribute.attname AS column_name FROM pg_index index_data JOIN pg_class table ON table.oid = index_data.indrelid JOIN pg_class index_rel ON index_rel.oid = index_data.indexrelid JOIN pg_namespace namespace ON namespace.oid = table.relnamespace JOIN pg_am access_method ON access_method.oid = index_rel.relam LEFT JOIN LATERAL unnest(index_data.indkey) WITH ORDINALITY key_columns(attnum, position) ON true LEFT JOIN pg_attribute attribute ON attribute.attrelid = table.oid AND attribute.attnum = key_columns.attnum WHERE table.relnamespace NOT IN (SELECT oid FROM pg_namespace WHERE nspname LIKE 'pg_%' OR nspname = 'information_schema') AND namespace.nspname = 'public' ORDER BY namespace.nspname, table.relname, index_rel.relname, key_columns.position
getAllForeignKeysSql: SELECT tc.constraint_name, tc.table_schema, tc.table_name, kcu.column_name AS source_column, ccu.table_schema AS target_schema, ccu.table_name AS target_table, ccu.column_name AS target_column FROM information_schema.table_constraints tc JOIN information_schema.key_column_usage kcu ON kcu.constraint_catalog = tc.constraint_catalog AND kcu.constraint_schema = tc.constraint_schema AND kcu.constraint_name = tc.constraint_name JOIN information_schema.constraint_column_usage ccu ON ccu.constraint_catalog = tc.constraint_catalog AND ccu.constraint_schema = tc.constraint_schema AND ccu.constraint_name = tc.constraint_name WHERE tc.constraint_catalog = 'app' AND tc.constraint_type = 'FOREIGN KEY' AND tc.table_schema = 'public' ORDER BY tc.table_schema, tc.table_name, tc.constraint_name, kcu.ordinal_position
getTableStatusSql: SELECT c.relname AS table_name, CASE WHEN c.relkind IN ('v', 'm') THEN 'VIEW' ELSE 'BASE TABLE' END AS table_type,
n.nspname AS schema, c.oid, c.reltuples AS rows, CASE WHEN c.relkind IN ('v', 'm') THEN 1 ELSE 0 END AS is_view,
CASE WHEN p.partrelid IS NOT NULL THEN 1 ELSE 0 END AS partitioned FROM pg_class c JOIN pg_namespace n ON n.oid = c.relnamespace LEFT JOIN pg_partitioned_table p ON p.partrelid = c.oid WHERE c.relkind IN ('r', 'p', 'v', 'm') AND n.nspname NOT LIKE 'pg_%' AND n.nspname <> 'information_schema' AND n.nspname = 'public' AND c.relname = 'users' ORDER BY n.nspname, c.relname
getViewsSql: SELECT viewname AS view_name, schemaname AS table_schema, definition AS view_definition, 0 AS materialized FROM pg_views WHERE schemaname = 'public' ORDER BY schemaname, viewname
getViewDefinitionSql: SELECT definition FROM pg_views WHERE schemaname = 'public' AND viewname = 'users'
getIndexesSql: SELECT *, indexname AS index_name FROM pg_indexes WHERE tablename = 'users' AND schemaname = 'public'
getForeignKeysSql: SELECT tc.constraint_name, tc.table_schema, tc.table_name, kcu.column_name AS source_column, ccu.table_schema AS target_schema, ccu.table_name AS target_table, ccu.column_name AS target_column FROM information_schema.table_constraints tc JOIN information_schema.key_column_usage kcu ON kcu.constraint_catalog = tc.constraint_catalog AND kcu.constraint_schema = tc.constraint_schema AND kcu.constraint_name = tc.constraint_name JOIN information_schema.constraint_column_usage ccu ON ccu.constraint_catalog = tc.constraint_catalog AND ccu.constraint_schema = tc.constraint_schema AND ccu.constraint_name = tc.constraint_name WHERE tc.table_schema = 'public' AND tc.table_name = 'users' AND tc.constraint_type = 'FOREIGN KEY' ORDER BY kcu.ordinal_position
getReferencingForeignKeysSql: SELECT tc.constraint_name, tc.table_schema, tc.table_name, kcu.column_name AS source_column, ccu.table_schema AS target_schema, ccu.table_name AS target_table, ccu.column_name AS target_column FROM information_schema.table_constraints tc JOIN information_schema.key_column_usage kcu ON kcu.constraint_catalog = tc.constraint_catalog AND kcu.constraint_schema = tc.constraint_schema AND kcu.constraint_name = tc.constraint_name JOIN information_schema.constraint_column_usage ccu ON ccu.constraint_catalog = tc.constraint_catalog AND ccu.constraint_schema = tc.constraint_schema AND ccu.constraint_name = tc.constraint_name WHERE ccu.table_schema = 'public' AND ccu.table_name = 'users' AND tc.constraint_type = 'FOREIGN KEY' ORDER BY kcu.ordinal_position
getTriggersSql: SELECT * FROM information_schema.triggers WHERE event_object_table = 'users'
getRoutinesSql: SELECT * FROM information_schema.routines WHERE routine_schema = 'public'
getCheckConstraintsSql: SELECT tc.constraint_name, cc.check_clause, 0 AS not_enforced FROM information_schema.table_constraints tc JOIN information_schema.check_constraints cc ON cc.constraint_name = tc.constraint_name AND cc.constraint_schema = tc.constraint_schema WHERE tc.table_schema = 'public' AND tc.table_name = 'users' AND tc.constraint_type = 'CHECK'
